+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'fr'; factor: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: number | {factor: number}};
+
+type Placement = {start: number; end: number};
+
+const trackPattern = /minmax\\([^)]*\\)|\\S+/g;
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	const fraction = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fraction) {
+		return {type: 'fr', factor: Number(fraction[1])};
+	}
+
+	const minmax = /^minmax\\((\\d*\\.?\\d+),\\s*(\\d*\\.?\\d+|\\d*\\.?\\d+fr)\\)$/.exec(
+		value,
+	);
+	if (minmax) {
+		const max = minmax[2]!;
+		const maxFraction = /^(\\d*\\.?\\d+)fr$/.exec(max);
+		return {
+			type: 'minmax',
+			min: Number(minmax[1]),
+			max: maxFraction ? {factor: Number(maxFraction[1])} : Number(max),
+		};
+	}
+
+	const size = Number(value);
+	if (Number.isFinite(size) && size >= 0) {
+		return {type: 'fixed', size};
+	}
+
+	throw new Error(`Invalid grid track size: ${value}`);
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	template ? (template.match(trackPattern) ?? []).map(parseTrack) : [];
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value === 'string') {
+		const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+		if (match && Number(match[1]) > 0 && Number(match[2]) > Number(match[1])) {
+			return {start: Number(match[1]) - 1, end: Number(match[2]) - 1};
+		}
+	}
