+const contentSize = (node: DOMElement, axis: 'width' | 'height'): number => {
+	const yogaNode = node.yogaNode!;
+	const isWidth = axis === 'width';
+	const start = isWidth ? Yoga.EDGE_LEFT : Yoga.EDGE_TOP;
+	const end = isWidth ? Yoga.EDGE_RIGHT : Yoga.EDGE_BOTTOM;
+	return Math.max(
