+			yogaNode.getComputedPadding(start) -
+			yogaNode.getComputedPadding(end) -
+			yogaNode.getComputedBorder(start) -
+			yogaNode.getComputedBorder(end),
+	);
+};
+
+const trackSizes = (
+	tracks: Track[],
+	available: number | undefined,
+	gapSize: number,
+	intrinsic: number[],
+): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.size;
+		if (track.type === 'auto') return intrinsic[index] ?? 0;
+		if (track.type === 'minmax') return track.min;
+		return 0;
+	});
